#!/usr/bin/env python3
"""Tally Bash + MCP tool calls from recent Claude Code transcripts."""
import json
import re
import shlex
from collections import Counter
from pathlib import Path

TRANSCRIPTS = Path("/tmp/cm_recent_transcripts.txt").read_text().strip().splitlines()

bash_counter: Counter = Counter()
mcp_counter: Counter = Counter()

ENV_VAR_RE = re.compile(r"^[A-Z_][A-Z0-9_]*=")


def normalize_bash(cmd: str) -> str | None:
    """Return a (command, first_subcommand) signature for tally purposes."""
    cmd = cmd.strip()
    if not cmd:
        return None
    # Take only the first segment before pipes/&&/||/;
    for sep in ["&&", "||", ";", "|"]:
        idx = cmd.find(sep)
        if idx != -1:
            cmd = cmd[:idx].strip()
    try:
        tokens = shlex.split(cmd, posix=True)
    except ValueError:
        return None
    # Strip leading env var assignments
    while tokens and ENV_VAR_RE.match(tokens[0]):
        tokens.pop(0)
    # Strip leading sudo / timeout / nice / etc.
    PREFIX_WRAPPERS = {"sudo", "timeout", "nice", "env", "command"}
    while tokens and tokens[0] in PREFIX_WRAPPERS:
        tokens.pop(0)
        # `env` might have its own VAR=val args
        while tokens and ENV_VAR_RE.match(tokens[0]):
            tokens.pop(0)
    if not tokens:
        return None
    head = tokens[0]
    # Drop absolute path component for binaries like /usr/bin/git
    if "/" in head:
        head = head.split("/")[-1]
    # Subcommand: first non-flag token after the head
    sub = ""
    for t in tokens[1:]:
        if not t.startswith("-"):
            sub = t
            break
    if sub:
        return f"{head} {sub}"
    return head


for path in TRANSCRIPTS:
    p = Path(path)
    if not p.exists():
        continue
    try:
        with p.open() as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    obj = json.loads(line)
                except json.JSONDecodeError:
                    continue
                msg = obj.get("message")
                if not isinstance(msg, dict):
                    continue
                if msg.get("role") != "assistant":
                    continue
                content = msg.get("content")
                if not isinstance(content, list):
                    continue
                for item in content:
                    if not isinstance(item, dict):
                        continue
                    if item.get("type") != "tool_use":
                        continue
                    name = item.get("name", "")
                    inp = item.get("input", {})
                    if name == "Bash":
                        cmd = inp.get("command", "") if isinstance(inp, dict) else ""
                        sig = normalize_bash(cmd)
                        if sig:
                            bash_counter[sig] += 1
                    elif name.startswith("mcp__"):
                        mcp_counter[name] += 1
    except OSError:
        continue

print("=== BASH (top 50) ===")
for sig, count in bash_counter.most_common(50):
    print(f"{count:>4}  {sig}")
print()
print("=== MCP ===")
for name, count in mcp_counter.most_common():
    print(f"{count:>4}  {name}")

